def longest_word(s):
    if not s:
        return ''

    words = s.split()
    if not words:
        return ''

    longest_word_so_far = ''
    for word in reversed(words):
        if len(word) >= len(longest_word_so_far):
            longest_word_so_far = word

    return longest_word_so_far
